/* こっちはテンプレートデザイナーで設定可 */
/*
<Group description="文字の色">
  <Variable name="font.color" description="普通の文字色" type="color"
   default="#454545" value="#555555"/>
  <Variable name="font.link" description="リンクの色" type="color"
   default="#0f2b46" value="#0f2b46"/>
  <Variable name="font.light" description="うす文字の色" type="color"
   default="#999" value="#999999"/>
</Group>

<Group description="ブランドカラー">
  <Variable name="brand.color" description="ブランドカラー" type="color"
   default="#0f2b46" value="#0f2b46"/>
  <Variable name="brand.font" description="ブランドカラー部分の文字色" type="color"
   default="#fff" value="#ffffff"/>
  <Variable name="brand.subcolor" description="ブランドサブカラー" type="color"
   default="#008db7" value="#008db7"/>
  <Variable name="brand.subfont" description="ブランドサブカラー部分の文字色" type="color"
   default="#0f2b46" value="#0f2b46"/>
</Group>

<Group description="背景色など">
  <Variable name="other.topback" description="最背景色" type="color"
   default="#f6f5f5" value="#f6f5f5"/>
  <Variable name="other.back" description="コンテンツの背景色" type="color"
   default="#fff" value="#ffffff"/>
  <Variable name="other.border" description="関連記事などのうすい枠線" type="color"
   default="#eee" value="#eeeeee"/>
</Group>
*/

/****************************************
もくじ
１初期化処理-*基本いじらない
２全体設定
３ナビゲーション
４ヘッダー
５パンくずリスト
６記事一覧
７個別記事
８サイドバー
９フッター
10個別アイテム（タグクラウド）
*****************************************/


/****************************************
     初期化処理-*基本いじらない
*****************************************/
abbr,address,article,aside,audio,b,blockquote,body,canvas,caption,cite,code,dd,del,details,dfn,div,dl,dt,em,fieldset,figcaption,figure,footer,form,h1,h2,h3,h4,h5,h6,header,hgroup,html,i,iframe,img,ins,kbd,label,legend,li,main,mark,menu,nav,object,ol,p,pre,q,samp,section,small,span,strong,sub,summary,sup,table,tbody,td,tfoot,th,thead,time,tr,ul,var,video{margin:0;padding:0;border:0;outline:0;font-size:100%;vertical-align:baseline;background:transparent}article,aside,details,figcaption,figure,footer,header,hgroup,main,menu,nav,section{display:block}blockquote,q{quotes:none}blockquote:after,blockquote:before,q:after,q:before{content:'';content:none}a{margin:0;padding:0;font-size:100%;vertical-align:baseline;background:transparent}ins{text-decoration:none}*,:after,:before{-webkit-box-sizing:border-box;-moz-box-sizing:border-box;-o-box-sizing:border-box;-ms-box-sizing:border-box;box-sizing:border-box}html{font-size:62.5%}body{text-align:left;word-wrap:break-word;overflow-wrap:break-word;font-size:1.7rem;font-weight:500;line-height:1.2;letter-spacing:.02em;min-width:960px}.container{margin:auto;width:86%;min-width:960px;max-width:1180px}a{text-decoration:none;color:inherit}img{height:auto;vertical-align:bottom}iframe,img{max-width:100%}.separator a{margin-left:0!important;margin-right:0!important}.separator a,.separator img{display:inline-block}.section{margin:0}.widget ol,.widget ul{padding:0}.widget-content li{list-style-type:none}.widget .post-body ol,.widget .post-body ul{padding-left:2em;padding-right:0}.Header h1{margin-bottom:0}.status-msg-wrap{margin:0}.status-msg-body{text-align:left}.status-msg-border{border:0}.status-msg-bg{background:0}.gsc-search-box{margin-bottom:0!important}table.gsc-search-box{background:#fff;border-radius:18px;max-width:16em}input.gsc-search-button{-webkit-appearance:none;-moz-appearance:none;appearance:none;padding:0 .8em;border:0;outline:0;margin-left:0!important;border-radius:18px;font-weight:700;height:2.5em;font-size:14px;cursor:pointer}.gsc-input{padding-right:0!important}input.gsc-input{-webkit-appearance:none;-moz-appearance:none;appearance:none;padding:0 1em;border:0;outline:0;background:#fff;border-radius:18px;height:2.5em;font-size:14px;width:100%}.cloud-label-widget-content{text-align:left}.label-size{font-size:80%!important;opacity:1!important;display:inline-block}@media(max-width:768px){body{font-size:1.6rem;min-width:0}.container{width:96%;min-width:0}.twitter-timeline{width:770px!important}}@media(max-width:480px){#main.width-100 .container{width:100%}.width-100 #sub-content,.width-100 .breadcrumbs{width:96%;margin-right:auto;margin-left:auto}}

/****************************************
          全体設定
*****************************************/

body {
   font-family: "游ゴシック体", "Yu Gothic", YuGothic, "ヒラギノ角ゴシック Pro", "Hiragino Kaku Gothic Pro", 'メイリオ', Meiryo, Osaka, "ＭＳ Ｐゴシック", "MS PGothic", sans-serif;
   background: $(other.topback);
   color: $(font.color);
}
/* 2カラム設定 */

#main-inner {
   display: flex;
}
#main-content {
   margin-right: 30px;
   width: calc(100% - 346px);
   flex-shrink: 0;
}
#sub-content {
   margin-top: 30px;
   width: 316px;
   flex-shrink: 0;
}
@media ( max-width: 768px) {
   #main-inner {
      display: block;
   }
   #main-content {
      margin-right: 0;
      width: 100%;
   }
   #sub-content {
      width: 100%;
   }
}
#site-header-wrap {
   overflow: visible !important;
   position: relative;
   width: 100%;
   /* 横幅を画面いっぱいに広げる */
}
#site-header-wrap::after {
   content: "";
   position: absolute;
   top: 0;
   right: 0;
   /* left: 100% ではなく、右端(0)を基準にする */
   left: auto;
   /* left指定を打ち消す */
   /* 要素が右に突き出さないように最大幅を制限 */
   max-width: 100%;
}
body {
   overflow-x: hidden;
}
a:hover {
   color: rgba(15, 43, 70, 0.7) !important;
   /* #0f2b46を透明度70%に */
   text-decoration: none;
   /* 下線を消す、あるいは追加する等の調整用 */
}
html, body {
   overflow-x: hidden;
   /* 突き出し(100vw)をブラウザに無視させる */
   width: 100%;
   margin: 0;
   padding: 0;
}
/****************************************
          ヘッダー＋ナビゲーション（修正済）
*****************************************/

/* ─ ラッパー ─ */

#site-header-wrap {
   display: flex;
   align-items: center;
   background: $(brand.color);
   color: $(brand.font);
   width: 86%;
   max-width: 1180px;
   min-width: 960px;
   margin-left: auto;
   margin-right: auto;
   position: relative;
   /* overflow: hiddenは絶対に使わない */
   overflow: visible !important;
}
/* 背景を画面端まで伸ばす（横スクロールの原因を特定して修正） */

#site-header-wrap::before, #site-header-wrap::after {
   content: '';
   position: absolute;
   top: 0;
   bottom: 0;
   width: 100vw;
   /* 視覚的に端まで伸ばす */
   background: $(brand.color);
   z-index: -1;
}
#site-header-wrap::before {
   right: 100%;
}
#site-header-wrap::after {
   left: 100%;
}
/* ─ ヘッダー（左）─ */

#header {
   flex-shrink: 0;
}
#header a {
   color: inherit;
}
#header-inner {
   padding: 0.8em 0;
   display: flex;
   align-items: center;
}
#header-inner .container {
   width: auto !important;
   max-width: none !important;
   min-width: 0 !important;
   margin: 0 !important;
   padding: 0 !important;
}
#header-title {
   font-size: 110%;
   font-weight: bold;
   white-space: nowrap;
}
#header a {
   color: #ffffff !important;
}
#header-text {
   display: none;
}
#header-img-wrapper {
   text-align: center;
}
/* ─ ナビゲーション（右）─ */

#navigation {
   flex: 1;
   display: flex;
   align-items: center;
   justify-content: flex-end;
   background: transparent;
   color: $(brand.font);
}
#navigation a {
   color: inherit;
}
#navigation .container {
   width: auto !important;
   max-width: none !important;
   min-width: 0 !important;
   margin: 0 !important;
   padding: 0 !important;
   display: flex;
   align-items: center;
   justify-content: flex-end;
   flex: 1;
}
#navigation-button, #navigation-label {
   display: none;
}
#PageList1 .widget-content {
   display: flex;
   flex-direction: row-reverse;
   align-items: center;
   padding: 0;
   position: static;
}
#navigation-content {
   display: flex;
   align-items: center;
}
#navigation-content ul {
   display: flex;
   flex-wrap: nowrap;
   margin: 0;
   padding: 0;
   list-style: none;
}
#navigation-content li {
   list-style: none;
}
#navigation-content li a {
   display: block;
   padding: 0.9em 1.1em;
   font-weight: bold;
   white-space: nowrap;
   transition: background 0.3s;
}
#navigation-content li a:hover {
   background: rgba(255, 255, 255, 0.15);
}
#PageList1 ul.menu-ready li a:hover {
   color: #7b8997 !important;
}
/* 検索フォーム */

#search-box-form {
   display: flex;
   align-items: center;
   background: rgba(255, 255, 255, 0.18);
   border-radius: 16px;
   padding: 0 0.4em;
   margin-left: 0.8em;
   height: 32px;
   width: 160px;
   float: none;
   position: static;
   transform: none;
}
#search-box-text {
   background: transparent;
   border: none;
   outline: none;
   color: $(brand.font);
   font-size: 0.88em;
   width: 100%;
   padding-left: 6px;
}
#search-box-text::placeholder {
   color: rgba(255, 255, 255, 0.6);
}
#search-box-submit {
   display: flex;
   align-items: center;
   background: none;
   border: none;
   outline: none;
   color: $(brand.font);
   cursor: pointer;
   padding: 0 4px;
   font-size: 0.9em;
   position: static;
   transform: none;
   height: auto;
   top: auto;
}
/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   プルダウンメニュー
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */

/* JS実行まで文字を隠す（ちらつき防止） */

#PageList1 ul li a {
   visibility: hidden;
   opacity: 0;
   transition: opacity 0.15s ease;
}
#PageList1 ul.menu-ready li a {
   visibility: visible;
   opacity: 1;
}
/* 親アイテム（子あり） */

#PageList1 ul li.has-sub {
   position: relative;
   cursor: pointer;
}
/* ▼アイコン */

#PageList1 ul li.has-sub>a::after {
   content: '\f078';
   font-family: "Font Awesome 5 Free";
   font-weight: 900;
   font-size: 10px;
   margin-left: 6px;
   display: inline-block;
   transition: transform 0.25s;
   visibility: visible;
}
/* 開いたときにアイコンを反転 */

#PageList1 ul li.has-sub.open>a::after {
   transform: rotate(180deg);
}
/* サブメニュー本体 */

#PageList1 ul li .sub-menu {
   display: none;
   position: absolute;
   top: 100%;
   left: 0;
   z-index: 1000;
   background: #ffffff;
   border: 1px solid #dddddd;
   border-radius: 4px;
   min-width: 180px;
   box-shadow: 0 4px 10px rgba(0, 0, 0, 0.12);
   padding: 4px 0;
   margin: 0;
   list-style: none;
}
/* .open のときだけ表示 */

#PageList1 ul li.has-sub.open>.sub-menu {
   display: block;
}
/* サブメニューのリンク */

#PageList1 ul li .sub-menu li {
   display: block;
   border-top: none;
}
#PageList1 ul li .sub-menu li a {
   display: block;
   padding: 0.65em 1.2em;
   color: #333 !important;
   font-weight: normal;
   white-space: nowrap;
   transition: background 0.2s;
   visibility: visible;
}
#PageList1 ul li .sub-menu li a:hover {
   background: #f0f4f8;
}
/* ─ スマホ：サブメニューは絶対配置をやめて縦積み ─ */

@media ( max-width: 768px) {
   #PageList1 ul li .sub-menu {
      position: static;
      box-shadow: none;
      border: none;
      border-top: 1px solid rgba(0, 0, 0, 0.06);
      background: rgba(0, 0, 0, 0.04);
      min-width: 0;
      padding: 0;
      border-radius: 0;
   }
   #PageList1 ul li .sub-menu li a {
      padding: 0.65em 2em;
      color: $(brand.subfont) !important;
   }
}
/* ─ スマホ（768px以下）─ */

@media ( max-width: 768px) {
   #site-header-wrap {
      display: block;
      width: 100%;
      max-width: 100%;
      min-width: 0;
   }
   #site-header-wrap::before, #site-header-wrap::after {
      display: none;
   }
   #header-inner {
      padding: 0.8em 2%;
   }
   #navigation {
      display: block;
      background: $(brand.subcolor);
      color: $(brand.subfont);
   }
   #navigation .container {
      display: block !important;
      width: 100% !important;
   }
   #navigation a {
      color: $(brand.subfont);
   }
   #navigation-label {
      display: block;
      text-align: center;
      padding: 0.8em;
      cursor: pointer;
      font-size: 1.4em;
   }
   #PageList1 .widget-content {
      display: block;
   }
   #navigation-content {
      display: none;
      flex-direction: column;
   }
   #navigation.open #navigation-content {
      display: flex;
   }
   #navigation-content ul {
      display: block;
   }
   #navigation-content li {
      border-top: 1px solid rgba(0, 0, 0, 0.08);
   }
   #navigation-content li a {
      padding: 0.8em 1.2em;
      color: $(brand.subfont);
   }
   #search-box-form {
      background: rgba(0, 0, 0, 0.07);
      border-radius: 4px;
      margin: 0.5em 1em;
      width: calc(100% - 2em);
      height: 38px;
      position: static;
      transform: none;
      float: none;
   }
   #search-box-text {
      color: $(brand.subfont);
   }
   #search-box-text::placeholder {
      color: rgba(0, 0, 0, 0.4);
   }
   #search-box-submit {
      color: $(brand.subfont);
   }
}
/****************************************
        パンくずリスト
*****************************************/

.breadcrumbs {
   line-height: 1;
   font-size: 14px;
   margin-top: 8px;
   background: inherit;
   color: $(font.light);
}
/* 404メッセージ */

.status-msg-wrap {
   color: $(font.light);
}
/* パンくずリスト全体のフォントサイズ調整 */

.breadcrumbs {
   font-size: 14px;
   color: #555555;
   padding: 10px 0;
   /* 動的に出力される「 / 」（テキストノード）を消去する */
   font-size: 0;
}
/* リンクとテキストの再表示 */

.breadcrumbs a, .breadcrumbs span {
   font-size: 14px;
   /* ここで文字サイズを戻す */
   color: #555555;
   text-decoration: none;
}
/* 「 / 」の代わりに Font Awesome を挿入 */

.breadcrumbs span:not(:last-child):after {
   content: '\f105';
   /* angle-right */
   font-family: "Font Awesome 5 Free";
   font-weight: 900;
   margin: 0 10px;
   color: #cccccc;
   font-size: 12px;
   display: inline-block;
}
/****************************************
        記事一覧
*****************************************/

#list {
   display: flex;
   flex-wrap: wrap;
   justify-content: space-between;
   align-items: stretch;
   /* 子要素（.list-item）の高さを自動で揃える */
}
#list a {
   color: inherit;
}
.list-item {
   flex-basis: 49.5%;
   margin-top: 8px;
   margin-bottom: 15px;
   border-radius: 3px;
   background: $(other.back);
   /* 内部コンテンツを縦に並べて高さを制御する */
   display: flex;
   flex-direction: column;
}
.list-item-inner {
   padding: .5em;
   border-top: none;
   /* 内部を縦並びのFlexboxにし、余白を埋める */
   display: flex;
   flex-direction: column;
   flex-grow: 1;
}
.list-item-date {
   color: $(font.light);
   font-size: 80%;
}
.list-item-category {
   display: flex;
   flex-wrap: wrap;
   justify-content: flex-end;
   font-size: 80%;
   font-weight: bold;
   /* タイトルが短い場合でも、カテゴリを常に最下部に固定する */
   margin-top: auto;
   padding-top: .5em;
}
.list-item-category-item {
   display: block;
   margin-top: .1em;
   margin-left: .1em;
   padding: .3em 1em;
   border-radius: 2px;
   background: $(brand.color);
   color: $(brand.font);
}
.list-item-img {
   display: block;
   width: 100%;
}
.list-item-title {
   margin-top: .5em;
   font-weight: bold;
   /* この要素に伸びる性質を持たせ、下の要素を押し下げる */
   flex-grow: 1;
}
.list-item-snippet {
   display: -webkit-box;
   -webkit-box-orient: vertical;
   -webkit-line-clamp: 3;
   overflow: hidden;
   margin-top: 8px;
   font-size: 14px;
   color: #666;
   line-height: 1.6;
   font-weight: normal;
}
@media ( max-width: 480px) {
   #list {
      display: block;
   }
}
/* メインコンテンツのリストアイテムのみを相対配置に */

#main .list-item {
   position: relative;
}
/* メインコンテンツのカテゴリラベルのみを絶対配置（左上固定）に */

#main .list-item-category {
   position: absolute;
   top: 0;
   left: 0;
   opacity: 1;
   /* 常時表示 */
   z-index: 10;
   margin-top: 0;
}
/* マウスホバー時の挙動もメイン限定に */

#main .list-item:hover .list-item-img {
   opacity: .7;
}
/* モバイル・タブレットでも常時表示（もし消したい場合は display: none） */

@media (max-width: 1024px) {
   #main .list-item-category {
      display: block;
   }
}
/* --- サイドバーなど他の場所のスタイルをリセット/維持 --- */

#sub-content .list-item-category {
   position: static;
   /* 通常の配置に戻す */
   opacity: 1;
   display: flex;
   /* 元の並びを維持 */
}
/* 目次コンテナ */

.custom-toc {
   background: #f9f9f9;
   border: 1px solid #aaa;
   padding: 15px;
   margin: 20px auto !important;
   width: 90%;
   max-width: 600px;
   font-size: 95%;
   box-sizing: border-box;
}
.custom-toc p {
   text-align: center;
   font-weight: bold;
   border-bottom: 1px solid #ccc;
   padding-bottom: 10px;
   margin-bottom: 10px;
}
/* トグル動作 */

.custom-toc.hide .toc-content {
   display: none !important;
}
/* リスト初期化 */

.custom-toc ul {
   list-style: none !important;
   margin: 0 !important;
   padding: 10px !important;
   border: none !important;
}
.custom-toc li {
   position: relative;
   list-style: none !important;
   margin: 0 !important;
   padding: 0 !important;
   border: none !important;
   display: block !important;
}
/* インデント */

.custom-toc .toc-item-h2 {
   margin-left: 0 !important;
}
.custom-toc .toc-item-h3 {
   margin-left: 1.5em !important;
}
.custom-toc .toc-item-h4 {
   margin-left: 3.0em !important;
}
/* リンク設定 */

.custom-toc a {
   text-decoration: none;
   color: #008db7!important;
   display: inline-flex;
   align-items: flex-start;
   background: none !important;
}
.custom-toc .toc-number {
   margin-right: 0.5em;
   white-space: nowrap;
}
/****************************************
        個別記事
*****************************************/

#single {
   padding: 2em;
   margin-top: 8px;
   background: $(other.back);
}
/* 個別記事見出し */

#singler-header {}
#single-header-date {
   font-size: 80%;
   margin-top: 1.25em;
   color: $(font.light);
}
#single-header-title {
   font-size: 2.3rem;
   font-weight: bold;
}
#single-header .single-share {
   margin-top: 1em;
}
#single-header-category {
   display: flex;
   flex-wrap: wrap;
   justify-content: flex-end;
   margin-top: .5em;
   font-size: 80%;
   font-weight: bold;
}
.single-header-category-item, {
   display: block;
   margin-top: .1em;
   margin-left: .1em;
   padding: .3em 1em;
   border-radius: 2px;
   background: $(brand.color);
   color: $(brand.font);
}
a.single-header-category-item:hover, .list-item-category-item a:hover {
   color: #ccc !important;
}
/* アドセンスのデザイン指定 */

#ad-1 {
   /* アドセンス広告1を使う場合有効にする */
   /* margin-top: 1em; */
   overflow: hidden;
}
#ad-2 {
   margin-top: 2em;
   overflow: hidden;
}
/* 個別記事本文 */

#single-content {
   margin-top: 1em;
   line-height: 1.8;
}
#single-content p {
   margin-top: 1.8em;
   margin-bottom: 1.8em;
}
#single-content a {
   color: $(font.link);
}
#single-content h2 {
   font-size: 2.26rem;
   font-weight: bold;
   padding: .8em .5em;
   margin-bottom: 1em;
   margin-top: 2em;
   border-radius: 2px;
   line-height: 1.2;
   background: $(brand.color);
   color: $(brand.font);
}
#single-content h3 {
   font-size: 2.26rem;
   font-weight: bold;
   margin-bottom: 1em;
   margin-top: 2em;
   padding: .5em 0;
   line-height: 1.2;
   border-bottom: solid 2px $(brand.color);
}
#single-content h4 {
   display: inline-block;
   font-weight: bold;
   border-left: solid 3px #0f2b46;
   margin: 0 auto 50px;
   padding: 5px 0 5px 5px;
}
#single-content blockquote {
   position: relative;
   padding: 7px 16px;
   box-sizing: border-box;
   color: #585858;
   border: solid 3px #585858;
}
#single-content blockquote:before {
   display: inline-block;
   position: absolute;
   top: -20px;
   left: -20px;
   width: 40px;
   height: 40px;
   line-height: 40px;
   border-radius: 50%;
   text-align: center;
   content: "\f10d";
   font-family: FontAwesome;
   background: #585858;
   color: #FFF;
   font-size: 22px;
}
#single-content blockquote:after {
   display: inline-block;
   position: absolute;
   bottom: -20px;
   right: -20px;
   width: 40px;
   height: 40px;
   line-height: 40px;
   border-radius: 50%;
   text-align: center;
   content: "\f10e";
   font-family: FontAwesome;
   background: #585858;
   color: #FFF;
   font-size: 22px;
   font-weight: 900;
}
#single-content blockquote p {
   padding: 0;
   margin: 10px 0;
   line-height: 1.7;
}
#single-content blockquote cite {
   display: block;
   text-align: right;
   color: #888888;
   font-size: 0.9em;
}
/* 個別記事下部 */

#single-footer {}
/* SNSボタン */

/* シェアボタン全体のコンテナ */

.single-share {
   display: flex !important;
   /* 強制的に横並びを有効化 */
   flex-direction: row !important;
   /* 縦並びを禁止 */
   flex-wrap: nowrap !important;
   /* 改行を禁止 */
   width: 100% !important;
   margin: 0 !important;
   padding: 0 !important;
   box-sizing: border-box;
}
/* 各ボタン（aタグ）の設定 */

.single-share a {
   display: flex !important;
   flex: 1 0 0% !important;
   /* 均等に横幅を埋め尽くす（5等分） */
   margin: 0 !important;
   padding: 0 !important;
   height: 44px;
   align-items: center;
