}
#footer .widget {
   padding-top: 30px;
}
#footer .widget:last-child {
   padding-bottom: 30px;
}
#footer .container {
   max-width: 1180px;
   margin: 0 auto !important;
   width: 86% !important;
}
#copyright {
   text-align: center;
   font-size: 70%;
   margin-top: 1em;
   color: $(font.light);
   letter-spacing: 0;
}
#copyright:before {
   content: "Copyright \0a9 ";
}
#copyright:after {
   content: " All Rights Reserved.";
}
#designed-by {
   text-align: right;
   font-size: 70%;
   margin-bottom: 1em;
   color: $(font.light);
   letter-spacing: 0;
}
#designed-by:before {
   content: "Original Designed by ";
}
#customize-by {
   text-align: right;
   font-size: 70%;
   margin-bottom: 1em;
   color: $(font.light);
   letter-spacing: 0;
}
#customize-by:before {
   content: "Customize Designed by ";
}
.container #designed-by a:hover, .container #customize-by a:hover {
   color: #ffffff !important;
}
.Attribution {
   color: $(font.light);
   font-size: 70%;
}
.Attribution a {
   color: inherit !important;
}
@media ( max-width: 768px) {
   #footer-inner {
      display: block;
   }
}
/****************************************
        個別アイテム
*****************************************/

/* タグクラウド */

.label-size {
   padding: .5em;
   border-radius: 3px;
   margin: .25em 0;
   background: $(brand.subcolor);
   color: $(brand.subfont);
}
.label-size a {
   color: inherit !important;
}
.widget h2 {
   font-size: 110%;
}
.widget h2, .widget .widget-content {
   font-weight: bold;
}
.popular-posts a {
   color: $(font.color) !important;
}
.post-summary h3 a {
   color: $(font.color) !important;
}
table.gsc-search-box {
   border: solid 1px $(other.border);
}
input.gsc-search-button {
   background: $(brand.subcolor);
   color: $(brand.subfont);
}
input.gsc-input {
   color: $(font.color);
}
/****************************************
        ページネーション
*****************************************/

.pagination {
   display: flex;
   flex-wrap: wrap;
   justify-content: center;
   gap: 6px;
   margin: 24px 0 16px;
}
.pagination-link {
   display: inline-flex;
   align-items: center;
   justify-content: center;
   min-width: 36px;
   height: 36px;
   padding: 0 10px;
   border: 1px solid #ddd;
   border-radius: 4px;
   background: #fff;
   color: #333;
   font-size: 14px;
   font-weight: bold;
   text-decoration: none;
   transition: background 0.2s, color 0.2s;
   cursor: pointer;
}
.pagination-link:hover {
   background: $(brand.color);
   color: $(brand.font) !important;
   border-color: $(brand.color);
}
.pagination-link.current-page {
   background: $(brand.color);
   color: $(brand.font);
   border-color: $(brand.color);
   cursor: default;
   pointer-events: none;
}

/****************************************
        吹き出しショートコード
*****************************************/

.balloon-simple {
   width: 100%;
   margin: 20px 0;
   overflow: hidden;
}
.balloon-simple .icon-right img, .balloon-simple .icon-left img {
   width: 100%;
   border-radius: 50%;
   background-size: cover;
}
.icon-right p, .icon-left p {
   text-align: center;
   top: -10px;
   position: relative;
   font-size: 12px;
   margin: 0;
}
.balloon-simple .balloon {
   width: 100%;
}
.serif-right, .serif-left {
   position: relative;
   padding: 15px 25px 15px 15px;
   border-radius: 10px;
}
.serif-right:after, .serif-left:after {
   content: "";
   position: absolute;
   top: 15px;
   border-top: 10px solid transparent;
   border-bottom: 5px solid transparent;
   border-left: 5px solid transparent;
}
.serif-right p, .serif-left p {
   margin: 0;
   padding: 0;
   color: #fff;
}
.balloon-simple .icon-right {
   float: right;
   width: 80px;
   margin-right: 10px;
}
.balloon-simple .icon-right img {
   border: solid 4px #85e3ff;
}
.serif-right {
   margin: 10px 100px 0 0;
   background: #85e3ff;
   float: right;
}
.serif-right:after {
   transform: scale(-1, 1);
   right: -22px;
   border-right: 20px solid #85e3ff;
}
.balloon-simple .icon-left {
   float: left;
   width: 80px;
   margin-left: 10px;
}
.balloon-simple .icon-left img {
   border: solid 4px #da9e5b;
}
.serif-left {
   display: inline-block;
   margin: 10px 0 0 110px;
   background: #da9e5b;
}
.serif-left:after {
   left: -22px;
   border-right: 20px solid #da9e5b;
}
@media (max-width: 480px) {
   .balloon-simple .icon-right, .balloon-simple .icon-left {
      width: 60px;
   }
   .serif-right {
      margin-right: 80px;
   }
   .serif-left {
      margin-left: 80px; }
}

b:if.script:
const rp_current = "";
const rp_max = 6; // 表示記事数
const rp_head = "関連記事"; // タイトル

//
(function(root, func) {
  if (!root.RelatedPosts) {
    root.RelatedPosts = func();
  }
})(this, function() {
  let _this = function RelatedPosts_constructor() {};
  let count = 0;
  let limit = 0;
  let urls = [];
  let titles = [];
  let dates = [];
  let imgs = [];

  // フィード数分をカウント
  _this.counter = function RelatedPosts_counter() {
    limit++;
  };

  // 関連記事の書き込み
  function RelatedPosts_write() {
    // 重複処理
    let dups = [];
    let indexs = [];
    for (let i = 0; i < urls.length; i++) {
      if (dups.indexOf(urls[i]) == -1) {
        dups.push(urls[i]);
        indexs.push(i);
      }
    }

    // ランダムインデックス生成
    let idx, items = [];
    let a = [...Array(indexs.length).keys()];
    while (a.length > 0) {
      idx = Math.floor(Math.random() * a.length);
      items.push(a[idx]);
      a.splice(idx, 1);
    }

    // 関連一覧の作成
    let html;
    let i = 0;
    if (indexs.length > 0) {
      html = '<div class="related-text">' + rp_head + '</div><div class="p-container">';
      while (i < indexs.length && i < rp_max) {
        html += '<a href="' + urls[indexs[items[i]]] + '"><figure class="related-img"><img alt="" width="250" height="150" src="' + imgs[indexs[items[i]]] + '"/></figure><div class="related-date">' + dates[indexs[items[i]]] + '</div><div class="related-title">' + titles[indexs[items[i]]] + '</div></a>';
        i++;
      }
      html += '</div>';
      document.getElementById("related-posts").innerHTML = html;
    }
  }

  // フィードデータ追加
  _this.add = function RelatedPosts_add(json) {
    let m = rp_current.match(/^https?:\/\/(.+$)/);
    let http  = '';
    let https = '';
    if (m != null) {
      http  = 'http://' + m[1];
      https = 'https://' + m[1];
    }
    for (let i = 0; i < json.feed.entry.length; i++) {
      let entry = json.feed.entry[i];
      for (let j = 0; j < entry.link.length; j++) {
        if (entry.link[j].rel == 'alternate') {
          if (!(http == entry.link[j].href || https == entry.link[j].href)) {
            urls.push(entry.link[j].href);
            titles.push(entry.title.$t);
            let date = entry.published.$t.substr(0, 10).replace(/-/g, "/");
            dates.push(date);
            let img;
            if ("media$thumbnail" in entry) {
              img = entry.media$thumbnail.url;
              let re1 = /\/s72-.*\//;
              let re2 = /=s72-.*$/;
              if (img.match(re1)) {
                img = img.replace(re1, '/w250-h150-n/');
              } else if (img.match(re2)) {
                img = img.replace(re2, '=w250-h150-n');
              } else if (img.match(/default.jpg/)) {
                img = img.replace('default.jpg', 'mqdefault.jpg');
              }
            } else {
              // NoImage画像
              img = "https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEiJGufis0idCDqb29dBvyQCx5M5dHTE4bpc52w6WGtcdKpsQImJUUvWSFYn5k_IDsn1TjOhyfzw51TgvvabIrVAYjxasRmPjGTPdSKudZTYD6JA5DLW2rm-9fkahTfV4Cmn-GjsDaiCDnJ5/w250-h150-n-e365/noimg.jpg";
            }
            imgs.push(img);
          }
          break;
        }
      }
    }
    count++;
    if (count == limit) {
      RelatedPosts_write();
    }
  };

  return _this;
});
//

(function() {
  let encoded = ""
  const keys = [/・/g, /&amp;/g, /#/g, /\//g];
  const reps = ["%E3%83%BB", "&", "%23", "%2F"];
  for (let i = 0; i < keys.length; i++) {
    encoded = encoded.replace(keys[i], reps[i]);
  }      
  const src = "/feeds/posts/summary/-/" + encoded + "?alt=json&max-results=10&callback=RelatedPosts.add";
  const js = document.createElement("script");
  js.type = "text/javascript";
  js.defer = true;
  js.src = src;
  document.head.appendChild(js);
}());

const blogUrl = "";
const label = "";
const query = "";
const selector = '.pagination';
const maxResults = 4;

//
setupPagination();

function setupPagination() {
  let currentPath = window.location.pathname;
  let base = blogUrl.replace(/\/$/, "");
  let feedUrl = base + '/feeds/posts/summary';

  let archiveMatch = currentPath.match(/\/(\d{4})\/(\d{2})\//);
  let isArchive = !!archiveMatch;

  if (isArchive) {
    let year = archiveMatch[1];
    let month = archiveMatch[2];
    let lastDay = new Date(year, month, 0).getDate();
    feedUrl += '?published-min=' + year + '-' + month + '-01T00:00:00';
    feedUrl += '&published-max=' + year + '-' + month + '-' + lastDay + 'T23:59:59';
  } else if (label) {
    feedUrl += '/-/' + encodeURIComponent(label);
  }

  feedUrl += (feedUrl.indexOf('?') <= -1 ? '?' : '&') + 'alt=json&max-results=1';

  if (query) {
    feedUrl = base + '/feeds/posts/summary?alt=json&max-results=99&q=' + encodeURIComponent(query);
  }

  fetch(feedUrl)
    .then(r => r.json())
    .then(json => {
      if (!json.feed || !json.feed.openSearch$totalResults) return;
      const totalResults = parseInt(json.feed.openSearch$totalResults.$t, 10);
      const totalPages = Math.ceil(totalResults / maxResults);

      let currentPage = 1;
      if (location.href.indexOf('#Page-') > -1) {
        currentPage = parseInt(location.href.split('#Page-')[1]);
      }

      if (totalResults > maxResults) {
        let pagerHtml = '';
        for (let i = 1; i <= totalPages; i++) {
          if (i === currentPage) {
            pagerHtml += '<span class="pagination-link current-page">' + i + '</span>';
          } else {
            pagerHtml += '<a class="pagination-link" id="Page-' + i + '" href="#">' + i + '</a>';
          }
        }
        const pagerElem = document.querySelector(selector);
        if (pagerElem) {
          pagerElem.innerHTML = pagerHtml;
          for (let i = 1; i <= totalPages; i++) {
            if (i === currentPage) continue;
            setPageUrl(i, isArchive, archiveMatch);
          }
        }
      }
    });
}

function setPageUrl(targetPage, isArchive, archiveMatch) {
  let startIndex = (targetPage - 1) * maxResults;
  if (startIndex <= 0) startIndex = 1;

  let base = blogUrl.replace(/\/$/, "");
  let feedUrl = base + "/feeds/posts/summary";
  let currentPath = window.location.pathname;

  if (isArchive) {
    let year = archiveMatch[1];
    let month = archiveMatch[2];
    let lastDay = new Date(year, month, 0).getDate();
    feedUrl += '?published-min=' + year + '-' + month + '-01T00:00:00';
    feedUrl += '&published-max=' + year + '-' + month + '-' + lastDay + 'T23:59:59';
  } else if (label != '') {
    feedUrl += '/-/' + encodeURIComponent(label);
  }
  feedUrl += (feedUrl.indexOf('?') <= -1 ? '?' : '&') + 'alt=json&orderby=published&start-index=' + startIndex + '&max-results=1';

  fetch(feedUrl)
    .then((response) => response.json())
    .then((json) => {
      if (!json.feed || !json.feed.entry) return;
      const date = encodeDate(json.feed.entry[0].published.$t);

      let hrefBase = isArchive ? (base + currentPath) : (base + '/search' + (label != '' ? '/label/' + encodeURIComponent(label) : ''));
      let finalHref = hrefBase.replace(/\/$/, "") + '?updated-max=' + date + '&max-results=' + maxResults + '&start=' + startIndex + '&by-date=false#Page-' + targetPage;

      const liElem = document.querySelector(selector + ' #Page-' + targetPage);
      if (liElem) liElem.href = finalHref;
    });
}

function encodeDate(dateStr) {
  dateStr = dateStr.substring(0, 19) + dateStr.substring(23, 29);
  return encodeURIComponent(dateStr);
}
