(function() {
  var initMenu = function() {
    var nav = document.getElementById('PageList1');
    if (!nav) return;

    var topUl = nav.querySelector('ul');
    if (!topUl) return;

    // li を配列に変換（DOMを操作するので先にコピー）
    var allItems = Array.prototype.slice.call(topUl.querySelectorAll(':scope > li'));
    var currentParent = null;

    allItems.forEach(function(item) {
      var link = item.querySelector('a');
      if (!link) return;
      var text = link.textContent.trim();

      if (text.charAt(0) === '_') {
        // 子アイテム：直前の親に追加
        if (currentParent) {
          var sub = currentParent.querySelector('ul.sub-menu');
          if (!sub) {
            sub = document.createElement('ul');
            sub.className = 'sub-menu';
            currentParent.appendChild(sub);
            currentParent.classList.add('has-sub');

            // 親ラベルクリック → サブメニュー開閉
            var parentLink = currentParent.querySelector('a');
            parentLink.addEventListener('click', function(e) {
              e.preventDefault();
              e.stopPropagation();
              // 他を閉じる
              var openItems = document.querySelectorAll('#PageList1 li.has-sub.open');
              for (var i = 0; i < openItems.length; i++) {
                if (openItems[i] !== currentParent) {
                  openItems[i].classList.remove('open');
                }
              }
              currentParent.classList.toggle('open');
            });
          }
          // 先頭の「_」を取り除く
          link.textContent = text.replace(/^_+/, '');
          sub.appendChild(item);
        }
      } else {
        // 通常アイテム → 次の親候補
        currentParent = item;
      }
    });

    // 準備完了 → 一斉に表示
    topUl.classList.add('menu-ready');

    // メニュー外クリックで全閉じ
    document.addEventListener('click', function() {
      var openItems = document.querySelectorAll('#PageList1 li.has-sub.open');
      for (var i = 0; i < openItems.length; i++) {
        openItems[i].classList.remove('open');
      }
    });
  };

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initMenu);
  } else {
    initMenu();
  }
})();
