jQuery(document).ready(function($){
  $('.lava-lamp-wrapper').each(function(){
    var $wrapper = $(this);
    var $buttons = $wrapper.find('.tab-buttons span');
    var $lamp = $wrapper.find('.lamp');
    var $contentDivs = $wrapper.find('.tab-content > div');
    var $tabContent = $wrapper.find('.tab-content');

    // ボタンの数から幅を自動計算 (2つなら50%, 3つなら33.33%...)
    var btnCount = $buttons.length;
    var lampWidth = 100 / btnCount;

    // 初期状態のランプ幅を設定
    $lamp.css('width', lampWidth + '%');

    $buttons.click(function(){
      var targetClass = $(this).attr('class');
      var index = $buttons.index(this);

      // ちらつき防止: 切り替え前に現在の高さを固定
      $tabContent.css('height', $tabContent.height());

      // ランプの移動：(インデックス × 幅) で正確な位置へ
      $lamp.css('left', (index * lampWidth) + '%');

      // コンテンツの切り替え
      $contentDivs.hide();
      var $nextContent = $wrapper.find('.tab-content > div.' + targetClass);

      $nextContent.fadeIn(400, function(){
        // フェード完了後に高さをオートに戻す
        $tabContent.css('height', 'auto');
      });
    });
  });
});
